#include <stdio.h>
#include <math.h>
int main() {
    int n;
    scanf("%d", &n);
    int x[n], y[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    int ans = 0;
    for (int i = 0; i < n - 1; i++) {
        ans += abs(x[i] - x[i + 1]) + abs(y[i] - y[i + 1]);
    }
    printf("%d\n", ans);
    return 0;
}

