import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] x = new int[n];
        int[] y = new int[n];
        for (int i = 0; i < n; i++) {
            x[i] = scanner.nextInt();
            y[i] = scanner.nextInt();
        }
        int ans = 0;
        for (int i = 0; i < n - 1; i++) {
            ans += Math.abs(x[i] - x[i + 1]) + Math.abs(y[i] - y[i + 1]);
        }
        System.out.println(ans);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let x = [];
let y = [];
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        let input = line.split(' ');
        x.push(parseInt(input[0]));
        y.push(parseInt(input[1]));
    }
    i++;
    if (i === n + 1) {
        let ans = 0;
        for (let j = 0; j < n - 1; j++) {
            ans += Math.abs(x[j] - x[j + 1]) + Math.abs(y[j] - y[j + 1]);
        }
        console.log(ans);
        readline.close();
    }
});
